// Reshape input to match original node expectations
const input = $input.first().json;
return [{json: {
  body: {
    meeting_name: input.meeting_name || '',
    participants: input.participants || '',
    date: input.date || '',
    start_time: input.start_time || '',
  },
  analyzedTopics: input.analyzedTopics || [],
  topics: input.topics || [],
  // Build Intel LLM Body expects $input.first().json shape
  // which is {minutes: "text"} — now accessed via $('Set Metadata').first().json.minutes
  minutes: input.assembledMinutesJson || {minutes: input.minutesText || ''},
  _transcript: input.transcript || {}
}}];

// Transcript already available from WF1 via orchestrator
// Original: HTTP GET to transcribe API for transcript JSON
// Now: extract from Set Metadata (passed through from WF1)
const meta = $('Set Metadata').first().json;
const transcript = meta._transcript || {};
return [{json: transcript}];

const data = $input.first().json;
const segments = data.segments || [];

const speakerStats = {};
for (const seg of segments) {
  const spk = seg.speaker || 'Unknown';
  if (!speakerStats[spk]) {
    speakerStats[spk] = { totalTime: 0, turns: 0, words: 0, longestTurn: 0, longestTurnText: '', longestTurnTs: 0 };
  }
  const s = speakerStats[spk];
  const dur = seg.end - seg.start;
  s.totalTime += dur;
  s.turns++;
  s.words += (seg.text || '').split(/\s+/).filter(w => w).length;
  if (dur > s.longestTurn) {
    s.longestTurn = dur;
    s.longestTurnText = (seg.text || '').substring(0, 100);
    s.longestTurnTs = seg.start;
  }
}

const totalDuration = segments.length ? segments[segments.length - 1].end : 1;

const interruptions = [];
for (let i = 1; i < segments.length; i++) {
  const prev = segments[i-1], curr = segments[i];
  const gap = curr.start - prev.end;
  if (prev.speaker !== curr.speaker && gap < 0.5 && gap > -1) {
    interruptions.push({ by: curr.speaker, interrupted: prev.speaker, at: curr.start, context: (prev.text || '').substring(0, 60) });
  }
}

const longPauses = [];
for (let i = 1; i < segments.length; i++) {
  const gap = segments[i].start - segments[i-1].end;
  if (gap > 5) {
    longPauses.push({ at: segments[i-1].end, duration: Math.round(gap), before: (segments[i-1].text || '').substring(0, 80), after: (segments[i].text || '').substring(0, 80) });
  }
}

const windowSize = 300;
const windows = {};
for (const seg of segments) {
  const w = Math.floor(seg.start / windowSize);
  windows[w] = (windows[w] || 0) + 1;
}
const energyCurve = Object.entries(windows).map(([w, c]) => ({ minuteMark: parseInt(w) * 5, turns: c }));

const fmt = s => `${Math.floor(s/60)}m${Math.round(s%60)}s`;
const ts  = s => new Date(s * 1000).toISOString().substr(11, 5);

let metricsText = `## QUANTITATIVE METRICS\n\n**Total duration:** ${fmt(totalDuration)}\n**Speakers:** ${Object.keys(speakerStats).length}\n\n### Talk Ratios\n`;
for (const [spk, s] of Object.entries(speakerStats)) {
  const ratio = Math.round(s.totalTime / totalDuration * 100);
  const wpm   = s.totalTime > 0 ? Math.round(s.words / (s.totalTime / 60)) : 0;
  metricsText += `- **${spk}**: ${ratio}% airtime (${fmt(s.totalTime)}), ${s.turns} turns, ~${wpm} WPM, longest: ${fmt(s.longestTurn)} at ${ts(s.longestTurnTs)}\n`;
  if (s.longestTurnText) metricsText += `  > "${s.longestTurnText}..."\n`;
}

metricsText += `\n### Interruptions (${interruptions.length} total)\n`;
if (interruptions.length === 0) {
  metricsText += `None detected.\n`;
} else {
  const byPair = {};
  for (const ir of interruptions) { const k = `${ir.by} \u2192 ${ir.interrupted}`; byPair[k] = (byPair[k]||0)+1; }
  for (const [pair, count] of Object.entries(byPair)) metricsText += `- ${pair}: ${count}x\n`;
}

metricsText += `\n### Long Pauses >5s (${longPauses.length} total)\n`;
for (const p of longPauses.slice(0, 5)) {
  metricsText += `- ${p.duration}s at ${ts(p.at)}: "...${p.before}" \u2192 "${p.after}..."\n`;
}
if (longPauses.length === 0) metricsText += `None detected.\n`;

metricsText += `\n### Energy Curve (turns per 5-min window)\n`;
metricsText += energyCurve.map(w => `- min ${w.minuteMark}: ${w.turns} turns`).join('\n') + '\n';

return [{ json: { metrics: metricsText, speakerStats, interruptions, longPauses, energyCurve, totalDuration } }];

const wb = $('Set Metadata').first().json.body;
const participants = wb.participants || [];
const meetingName  = wb.meeting_name || '';
const query = `meeting intelligence ELITE-INTEL-OMEGA behavioral analysis ${participants.join(' ')} ${meetingName}`;
return [{ json: { body: JSON.stringify({ query, n_results: 10, collection: 'vault' }) } }];

function estimateCtx(promptChars, responseTokens) {
  responseTokens = responseTokens || 2048;
  const promptTokens = Math.ceil(promptChars / 3.5);
  const raw = promptTokens + responseTokens;
  const rounded = Math.ceil(raw / 1024) * 1024;
  return Math.max(2048, Math.min(rounded, 49152));
}
// Fan out: one intel prompt per topic using the already-analyzed topic content
const topicResults = $('Set Metadata').first().json.analyzedTopics.map(t => ({json: t}));
const wb = $('Set Metadata').first().json.body;
const participants = wb.participants || [];
const participantStr = Array.isArray(participants) && participants.length ? participants.join(', ') : 'unknown';
const date = wb.date || new Date().toISOString().split('T')[0];

const systemPrompt = `You are a meeting intelligence analyst. For this SINGLE TOPIC, identify:
1. Key behavioral signals (who said what, tone, hedging, confidence levels)
2. Power dynamics and influence patterns
3. Hidden concerns or unspoken risks
4. Deception or withholding indicators (with confidence %)
5. Motivations and drivers for each speaker

Be evidence-based: cite specific quotes or paraphrases with speaker attribution.
Use wikilinks for person names: [[Lastname Firstname]] (family name first, ALWAYS reorder — e.g. "Johanna Aivio" becomes [[Aivio Johanna]]). First-name-only = plain text, no wikilink.
Output concise markdown (max 500 words). No preamble.`;

const items = topicResults.map(item => {
    const topicContent = item.json.response || '';
    const topicName = item.json.topicName || 'Topic';
    const topicIndex = item.json.topicIndex || 0;

    // Get the original topic transcript from Slice Topics
    const sliceItems = $('Set Metadata').first().json.topics.map(t => ({json: t}));
    const sliceItem = sliceItems.find(s => s.json.topicIndex === topicIndex);
    const topicTranscript = sliceItem ? sliceItem.json.topicTranscript || '' : '';

    // Cap per-topic transcript for 8b model
    const MAX_CHARS = 20000;
    const safeTranscript = topicTranscript.length > MAX_CHARS
        ? topicTranscript.substring(0, MAX_CHARS) + '\n[...truncated...]'
        : topicTranscript;

    const userMsg = `Topic: ${topicName}\nParticipants: ${participantStr}\nDate: ${date}\n\n## Meeting Minutes (this topic)\n${topicContent}\n\n## Raw Transcript (this topic)\n${safeTranscript}`;

    return {
        json: {
            topicIndex: topicIndex,
            topicName: topicName,
            body: JSON.stringify({
                model: 'qwen3.5:27b-32k',
                stream: false,
                think: false,
                num_ctx: estimateCtx((systemPrompt || "").length + (userMsg || "").length),
                system: systemPrompt,
                prompt: userMsg
            })
        }
    };
});

return items;

const item = $input.item.json;
const bodyObj = JSON.parse(item.body);

const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:11434/api/generate',
    body: bodyObj,
    headers: {'Content-Type': 'application/json'},
    timeout: 600000,
    returnFullResponse: false,
    json: true,
});

return {
    json: {
        topicIntel: result.response || '',
        topicIndex: item.topicIndex,
        topicName: item.topicName,
    }
};

function estimateCtx(promptChars, responseTokens) {
  responseTokens = responseTokens || 2048;
  const promptTokens = Math.ceil(promptChars / 3.5);
  const raw = promptTokens + responseTokens;
  const rounded = Math.ceil(raw / 1024) * 1024;
  return Math.max(2048, Math.min(rounded, 49152));
}
const wb           = $('Set Metadata').first().json.body;
const participants = wb.participants || [];
const meetingName  = wb.meeting_name || '';
const date         = wb.date || new Date().toISOString().split('T')[0];
const minutes      = $('Set Metadata').first().json.minutes.minutes || '';
const metrics      = $('Compute Metrics').first().json.metrics;
const ragResults   = $('Fetch Historical Context').first().json;
const ragChunks    = Array.isArray(ragResults)
    ? ragResults.map(r => r.text).join('\n\n---\n\n')
    : '';

// Collect per-topic intel analyses
const topicIntels = $('Analyze Topic Intel').all();
const intelSummaries = topicIntels
    .sort((a, b) => (a.json.topicIndex || 0) - (b.json.topicIndex || 0))
    .map(item => `### ${item.json.topicName}\n${item.json.topicIntel}`)
    .join('\n\n');

// Wikilink pre-validation
const ragLower = ragChunks.toLowerCase();
const confirmedInVault = participants.filter(p => ragLower.includes(p.toLowerCase().split(' ')[0]));

const systemPrompt = `You are ELITE-INTEL-OMEGA, a world-class Strategic Intelligence Analyst. Synthesize the per-topic intelligence analyses below into ONE cohesive Meeting Intelligence Report.

Your style: Formal yet razor-sharp. Zero fluff, maximum signal. Every inference is evidence-based. Assign explicit confidence %. Flag speculation as "hypothesis — needs external validation."

WIKILINK RULES: ALL person mentions MUST be wikilinks. Format: [[Lastname Firstname]] (family name first, ALWAYS reorder — e.g. "Johanna Aivio" becomes [[Aivio Johanna]]). [[Firstname]] if only first name known. People confirmed in vault: ${confirmedInVault.join(', ') || 'none confirmed — use [[Firstname]]'}.

OUTPUT FORMAT (strict Markdown):
# MEETING INTELLIGENCE REPORT
**Meeting**: ${meetingName} — ${date}
**Analyst**: ELITE-INTEL-OMEGA

## 1. Executive Summary
(3-5 bullets: highest-signal insights)

## 2. Participant Intelligence Profiles
(Per person: Role | Core Drivers + evidence | Key Fears + % | Leverage Points)

## 3. Linguistic & Behavioral Forensics
(Deception/Withholding clusters, Emotional Tone Map, Communication Patterns — reference metrics)

## 4. Secrets, Fears, Motivations & Hidden Agendas

## 5. Relationship & Power Dynamics
(Alliances/Tensions, Strategic Leverage)

## 6. Actionable Recommendations
(Immediate tactical + Strategic long-term + Monitoring signals)

## 7. Longitudinal Delta
(vs. previous meetings from historical context, or "First encounter — baseline established")

## 8. Obsidian PKMS Integration
(New wikilinks, atomic notes, MOC updates — all people as [[Name]])

Be ruthless in honesty, constructive in recommendations.`;

const userMsg = `## PER-TOPIC INTELLIGENCE ANALYSES
${intelSummaries}

---

## QUANTITATIVE METRICS
${metrics}

---

## HISTORICAL CONTEXT (vault excerpts)
${ragChunks || 'No historical context found.'}`;

return [{ json: { body: JSON.stringify({
    model: 'qwen3.5:27b-32k',
    stream: false,
    think: false,
    num_ctx: estimateCtx((systemPrompt || "").length + (userMsg || "").length),
    system: systemPrompt,
    prompt: userMsg
}) } }];

const wb          = $('Set Metadata').first().json.body;
const date        = wb.date || new Date().toISOString().split('T')[0];
const meetingName = wb.meeting_name || 'Meeting';
const resp        = $input.first().json;
const report      = resp.response || '';
if (!report) { return [{ json: { intelPath: '101 - Meeting Intelligence Reports/(intel skipped — LLM returned empty)' } }]; }

const now = new Date();
const _hTime = new Date(now.toLocaleString('en-US', {timeZone: 'Europe/Helsinki'}));
const _pad = n => String(n).padStart(2, '0');
const createdAt = `${_hTime.getFullYear()}-${_pad(_hTime.getMonth()+1)}-${_pad(_hTime.getDate())} ${_pad(_hTime.getHours())}:${_pad(_hTime.getMinutes())}`;

const safeName = meetingName.replace(/[\/\\:*?"<>|]/g, '-');
const path       = `101 - Meeting Intelligence Reports/${date} ${safeName} - Intelligence Report.md`;
const minutePath = `100 - Meeting minutes/${date} ${safeName}.md`;
const header     = `Intel report generated: ${createdAt}\nClassification: PERSONAL \u2014 RESTRICTED\nTemplate Version: M15.1\n\n---\n\n`;
const crossLink  = `\n\n---\n\n*Meeting Minutes: [[${minutePath}]]*`;

return [{ json: { body: JSON.stringify({ path, content: header + report + crossLink, overwrite: true }), intelPath: path } }];
